-- Add asset_group and asset_cat columns to equipment_types
ALTER TABLE equipment_types
  ADD COLUMN IF NOT EXISTS asset_group VARCHAR(100),
  ADD COLUMN IF NOT EXISTS asset_cat   VARCHAR(100);

-- Seed / update all 76 asset names from Plants_Machinery_Asset_Matrix.xlsx
-- asset_group  = Excel "Asset Group"
-- asset_cat    = Excel "Asset Category"
-- asset_category (existing) = Measurable | Non-Measurable
ON CONFLICT (name) DO UPDATE SET
  asset_group    = EXCLUDED.asset_group,
  asset_cat      = EXCLUDED.asset_cat,
  asset_category = COALESCE(EXCLUDED.asset_category, equipment_types.asset_category);
